mapper.update:
UPDATE LEARN_LIST
   SET TITLE = #{dto.title},
       START_DATE = TO_DATE(#{dto.startDate}, 'YYYY-MM-DD'),
       END_DATE = TO_DATE(SUBSTR(#{dto.deadline}, 1, 10), 'YYYY-MM-DD')
 WHERE CLASS_ID = #{classId}
   AND TEACHER_ID = #{teacherId}
   AND LEARN_LIST_ID = (
       SELECT LEARN_LIST_ID
       FROM LEARN_CONT
       WHERE LEARN_ID = #{learnId}
   )

UPDATE LEARN_CONT
   SET TITLE = #{dto.title},
       CONTENT = #{dto.content},
       REQUIRED_YN = CASE WHEN #{dto.required} = 'true' THEN 1 ELSE 0 END,
       START_DATE = TO_DATE(#{dto.startDate}, 'YYYY-MM-DD'),
       END_DATE = TO_DATE(SUBSTR(#{dto.deadline}, 1, 16), 'YYYY-MM-DD"T"HH24:MI'),
       TARGET_TIME = #{dto.duration},
       GUIDE_POINT = #{dto.textContent},
       ATTACH_URL = #{dto.linkUrl}
 WHERE LEARN_ID = #{learnId}
   AND LEARN_LIST_ID IN (
       SELECT LEARN_LIST_ID
       FROM LEARN_LIST
       WHERE CLASS_ID = #{classId}
         AND TEACHER_ID = #{teacherId}
   )

UPDATE LEARN_CONT
   SET DELETE_YN = 1,
       DELETED_AT = SYSDATE
 WHERE LEARN_ID = #{learnId}
   AND LEARN_LIST_ID IN (
       SELECT LEARN_LIST_ID
       FROM LEARN_LIST
       WHERE CLASS_ID = #{classId}
         AND TEACHER_ID = #{teacherId}
   )

UPDATE LEARN_CONT
   SET DELETE_YN = 0,
       DELETED_AT = NULL
 WHERE LEARN_ID = #{learnId}
   AND LEARN_LIST_ID IN (
       SELECT LEARN_LIST_ID
       FROM LEARN_LIST
       WHERE CLASS_ID = #{classId}
         AND TEACHER_ID = #{teacherId}
   )

