DELETE FROM LEARN_FBD
 WHERE PROGRESS_ID IN (
     SELECT PROGRESS_ID
     FROM LEARN_PRO
     WHERE LEARN_ID = #{learnId}
 )

DELETE FROM LEARN_CONT
 WHERE LEARN_ID = #{learnId}
   AND LEARN_LIST_ID IN (
       SELECT LEARN_LIST_ID
       FROM LEARN_LIST
       WHERE CLASS_ID = #{classId}
         AND TEACHER_ID = #{teacherId}
   )

DELETE FROM LEARN_LIST
 WHERE LEARN_LIST_ID IN (
     SELECT LL.LEARN_LIST_ID
     FROM LEARN_LIST LL
     WHERE LL.CLASS_ID = #{classId}
       AND LL.TEACHER_ID = #{teacherId}
       AND NOT EXISTS (
           SELECT 1
           FROM LEARN_CONT LC
           WHERE LC.LEARN_LIST_ID = LL.LEARN_LIST_ID
       )
 )
